#!/usr/bin/env python3
import os,sys,json,time,subprocess
def sh(c,t=25):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception as e: return "ERR:%s"%e
out={"kind":"async_err","ts":int(time.time())}
try:
    # full traceback from a bounded manual run with the unit's env
    out["manual_tb"]=sh("set -a; [ -f /etc/atlas/db.env ] && . /etc/atlas/db.env; [ -f /etc/atlas/autopull.env ] && . /etc/atlas/autopull.env; export ATLAS_ASYNC_LANES=2048 ATLAS_ASYNC_PG_POOL=12 ATLAS_ASYNC_DB_WRITERS=4; timeout 12 /opt/atlas/venv/bin/python /opt/atlas/importers/atlas_enrich_async.py 2>&1 | tail -25", t=20)
    # also try with tiny lanes to see if it's the 2048 config
    out["manual_tb_small"]=sh("set -a; [ -f /etc/atlas/db.env ] && . /etc/atlas/db.env; export ATLAS_ASYNC_LANES=8 ATLAS_ASYNC_PG_POOL=4 ATLAS_ASYNC_DB_WRITERS=2; timeout 15 /opt/atlas/venv/bin/python /opt/atlas/importers/atlas_enrich_async.py 2>&1 | tail -20", t=22)
    out["env_keys"]=sh("grep -oE '^[A-Z_]+=' /etc/atlas/db.env 2>/dev/null | tr '\\n' ' '")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/async-err.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"async_err","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
